// QR Code Generator Library - Local version
// Based on qrcode-generator by davidshimjs
// https://github.com/davidshimjs/qrcodejs

var qrcode = function(typeNumber, errorCorrectLevel) {
    var PAD0 = 0xEC;
    var PAD1 = 0x11;
    
    var qr = {};
    
    var typeNumber = typeNumber;
    var errorCorrectLevel = errorCorrectLevel || 'M';
    var modules = null;
    var moduleCount = 0;
    var dataCache = null;
    var dataList = [];
    
    qr.addData = function(data) {
        dataList.push(data);
        dataCache = null;
    };
    
    qr.isDark = function(row, col) {
        if (row < 0 || moduleCount <= row || col < 0 || moduleCount <= col) {
            throw new Error(row + "," + col);
        }
        return modules[row][col];
    };
    
    qr.getModuleCount = function() {
        return moduleCount;
    };
    
    qr.make = function() {
        makeImpl(false, getBestMaskPattern());
    };
    
    var makeImpl = function(test, maskPattern) {
        moduleCount = typeNumber * 4 + 17;
        modules = new Array(moduleCount);
        
        for (var row = 0; row < moduleCount; row++) {
            modules[row] = new Array(moduleCount);
            for (var col = 0; col < moduleCount; col++) {
                modules[row][col] = null;
            }
        }
        
        setupPositionProbePattern(0, 0);
        setupPositionProbePattern(moduleCount - 7, 0);
        setupPositionProbePattern(0, moduleCount - 7);
        setupPositionAdjustPattern();
        setupTimingPattern();
        setupTypeInfo(test, maskPattern);
        
        if (typeNumber >= 7) {
            setupTypeNumber(test);
        }
        
        if (dataCache == null) {
            dataCache = createData(typeNumber, errorCorrectLevel, dataList);
        }
        
        mapData(dataCache, maskPattern);
    };
    
    var setupPositionProbePattern = function(row, col) {
        for (var r = -1; r <= 7; r++) {
            if (row + r <= -1 || moduleCount <= row + r) continue;
            for (var c = -1; c <= 7; c++) {
                if (col + c <= -1 || moduleCount <= col + c) continue;
                if ( (0 <= r && r <= 6 && (c == 0 || c == 6) )
                    || (0 <= c && c <= 6 && (r == 0 || r == 6) )
                    || (2 <= r && r <= 4 && 2 <= c && c <= 4) ) {
                    modules[row + r][col + c] = true;
                } else {
                    modules[row + r][col + c] = false;
                }
            }
        }
    };
    
    var getBestMaskPattern = function() {
        var minLostPoint = 0;
        var pattern = 0;
        
        for (var i = 0; i < 8; i++) {
            makeImpl(true, i);
            var lostPoint = getLostPoint();
            if (i == 0 || minLostPoint > lostPoint) {
                minLostPoint = lostPoint;
                pattern = i;
            }
        }
        
        return pattern;
    };
    
    var getLostPoint = function() {
        var lostPoint = 0;
        
        // LEVEL1
        for (var row = 0; row < moduleCount; row++) {
            for (var col = 0; col < moduleCount; col++) {
                var sameCount = 0;
                var dark = qr.isDark(row, col);
                for (var r = -1; r <= 1; r++) {
                    if (row + r < 0 || moduleCount <= row + r) continue;
                    for (var c = -1; c <= 1; c++) {
                        if (col + c < 0 || moduleCount <= col + c) continue;
                        if (r == 0 && c == 0) continue;
                        if (dark == qr.isDark(row + r, col + c)) sameCount++;
                    }
                }
                if (sameCount > 5) lostPoint += (3 + sameCount - 5);
            }
        }
        
        // LEVEL2
        for (var row = 0; row < moduleCount - 1; row++) {
            for (var col = 0; col < moduleCount - 1; col++) {
                var count = 0;
                if (qr.isDark(row, col)) count++;
                if (qr.isDark(row + 1, col)) count++;
                if (qr.isDark(row, col + 1)) count++;
                if (qr.isDark(row + 1, col + 1)) count++;
                if (count == 0 || count == 4) lostPoint += 3;
            }
        }
        
        return lostPoint;
    };
    
    var setupPositionAdjustPattern = function() {
        var pos = getPatternPosition(typeNumber);
        
        for (var i = 0; i < pos.length; i++) {
            for (var j = 0; j < pos.length; j++) {
                var row = pos[i];
                var col = pos[j];
                
                if (modules[row][col] != null) continue;
                
                for (var r = -2; r <= 2; r++) {
                    for (var c = -2; c <= 2; c++) {
                        if (r == -2 || r == 2 || c == -2 || c == 2 || (r == 0 && c == 0)) {
                            modules[row + r][col + c] = true;
                        } else {
                            modules[row + r][col + c] = false;
                        }
                    }
                }
            }
        }
    };
    
    var setupTimingPattern = function() {
        for (var r = 8; r < moduleCount - 8; r++) {
            if (modules[r][6] != null) continue;
            modules[r][6] = (r % 2 == 0);
        }
        for (var c = 8; c < moduleCount - 8; c++) {
            if (modules[6][c] != null) continue;
            modules[6][c] = (c % 2 == 0);
        }
    };
    
    var setupTypeInfo = function(test, maskPattern) {
        var data = (getErrorCorrectLevel(errorCorrectLevel) << 3) | maskPattern;
        var bits = getBCHTypeInfo(data);
        
        // vertical
        for (var i = 0; i < 15; i++) {
            var mod = !test && ( (bits >> i) & 1) == 1;
            if (i < 6) {
                modules[i][8] = mod;
            } else if (i < 8) {
                modules[i + 1][8] = mod;
            } else {
                modules[moduleCount - 15 + i][8] = mod;
            }
        }
        
        // horizontal
        for (var i = 0; i < 15; i++) {
            var mod = !test && ( (bits >> i) & 1) == 1;
            if (i < 8) {
                modules[8][moduleCount - i - 1] = mod;
            } else if (i < 9) {
                modules[8][15 - i - 1 + 1] = mod;
            } else {
                modules[8][15 - i - 1] = mod;
            }
        }
        
        // fixed module
        modules[moduleCount - 8][8] = !test;
    };
    
    var setupTypeNumber = function(test) {
        var bits = getBCHTypeNumber(typeNumber);
        
        for (var i = 0; i < 18; i++) {
            var mod = !test && ( (bits >> i) & 1) == 1;
            modules[Math.floor(i / 3)][i % 3 + moduleCount - 8 - 3] = mod;
        }
        
        for (var i = 0; i < 18; i++) {
            var mod = !test && ( (bits >> i) & 1) == 1;
            modules[i % 3 + moduleCount - 8 - 3][Math.floor(i / 3)] = mod;
        }
    };
    
    var mapData = function(data, maskPattern) {
        var inc = -1;
        var row = moduleCount - 1;
        var bitIndex = 7;
        var byteIndex = 0;
        
        for (var col = moduleCount - 1; col > 0; col -= 2) {
            if (col == 6) col--;
            
            while (true) {
                for (var c = 0; c < 2; c++) {
                    if (modules[row][col - c] == null) {
                        var dark = false;
                        if (byteIndex < data.length) {
                            dark = ( ( (data[byteIndex] >>> bitIndex) & 1) == 1);
                        }
                        
                        var mask = getMask(maskPattern, row, col - c);
                        if (mask) dark = !dark;
                        
                        modules[row][col - c] = dark;
                        bitIndex--;
                        
                        if (bitIndex == -1) {
                            byteIndex++;
                            bitIndex = 7;
                        }
                    }
                }
                
                row += inc;
                if (row < 0 || moduleCount <= row) {
                    row -= inc;
                    inc = -inc;
                    break;
                }
            }
        }
    };
    
    var getMask = function(maskPattern, i, j) {
        switch (maskPattern) {
            case 0: return (i + j) % 2 == 0;
            case 1: return i % 2 == 0;
            case 2: return j % 3 == 0;
            case 3: return (i + j) % 3 == 0;
            case 4: return (Math.floor(i / 2) + Math.floor(j / 3)) % 2 == 0;
            case 5: return (i * j) % 2 + (i * j) % 3 == 0;
            case 6: return ((i * j) % 2 + (i * j) % 3) % 2 == 0;
            case 7: return ((i * j) % 3 + (i + j) % 2) % 2 == 0;
            default: throw new Error("bad maskPattern:" + maskPattern);
        }
    };
    
    var createData = function(typeNumber, errorCorrectLevel, dataList) {
        var rsBlocks = getRSBlocks(typeNumber, errorCorrectLevel);
        var buffer = [];
        
        for (var i = 0; i < dataList.length; i++) {
            var data = dataList[i];
            buffer.push(4); // mode
            buffer.push(data.length); // length
            for (var j = 0; j < data.length; j++) {
                buffer.push(data.charCodeAt(j));
            }
        }
        
        var totalDataCount = 0;
        for (var i = 0; i < rsBlocks.length; i++) {
            totalDataCount += rsBlocks[i].dataCount;
        }
        
        if (buffer.length > totalDataCount * 8) {
            throw new Error("code length overflow. (" + buffer.length + ">" + totalDataCount * 8 + ")");
        }
        
        // end code
        if (buffer.length + 4 <= totalDataCount * 8) {
            buffer.push(0);
            buffer.push(0);
            buffer.push(0);
            buffer.push(0);
        }
        
        // padding
        while (buffer.length % 8 != 0) {
            buffer.push(0);
        }
        
        // padding
        while (true) {
            if (buffer.length >= totalDataCount * 8) break;
            buffer.push(PAD0);
            if (buffer.length >= totalDataCount * 8) break;
            buffer.push(PAD1);
        }
        
        return createBytes(buffer, rsBlocks);
    };
    
    var createBytes = function(buffer, rsBlocks) {
        var offset = 0;
        var maxDcCount = 0;
        var maxEcCount = 0;
        var dcdata = new Array(rsBlocks.length);
        var ecdata = new Array(rsBlocks.length);
        
        for (var r = 0; r < rsBlocks.length; r++) {
            var dcCount = rsBlocks[r].dataCount;
            var ecCount = rsBlocks[r].totalCount - dcCount;
            
            maxDcCount = Math.max(maxDcCount, dcCount);
            maxEcCount = Math.max(maxEcCount, ecCount);
            
            dcdata[r] = new Array(dcCount);
            for (var i = 0; i < dcdata[r].length; i++) {
                dcdata[r][i] = 0xff & buffer[i + offset];
            }
            offset += dcCount;
            
            var rsPoly = getErrorCorrectPolynomial(ecCount);
            var rawPoly = {
                getAt: function(i) {
                    return dcdata[r][i];
                },
                getLength: function() {
                    return dcdata[r].length;
                }
            };
            
            var modPoly = mod(rawPoly, rsPoly);
            ecdata[r] = new Array(rsPoly.getLength() - 1);
            for (var i = 0; i < ecdata[r].length; i++) {
                var modIndex = i + modPoly.getLength() - ecdata[r].length;
                ecdata[r][i] = (modIndex >= 0)? modPoly.getAt(modIndex) : 0;
            }
        }
        
        var totalCodeCount = 0;
        for (var i = 0; i < rsBlocks.length; i++) {
            totalCodeCount += rsBlocks[i].totalCount;
        }
        
        var data = new Array(totalCodeCount);
        var index = 0;
        
        for (var i = 0; i < maxDcCount; i++) {
            for (var r = 0; r < rsBlocks.length; r++) {
                if (i < dcdata[r].length) {
                    data[index++] = dcdata[r][i];
                }
            }
        }
        
        for (var i = 0; i < maxEcCount; i++) {
            for (var r = 0; r < rsBlocks.length; r++) {
                if (i < ecdata[r].length) {
                    data[index++] = ecdata[r][i];
                }
            }
        }
        
        return data;
    };
    
    // Helper functions
    var getErrorCorrectLevel = function(errorCorrectLevel) {
        switch (errorCorrectLevel) {
            case 'L': return 1;
            case 'M': return 0;
            case 'Q': return 3;
            case 'H': return 2;
            default: throw new Error("errorCorrectLevel:" + errorCorrectLevel);
        }
    };
    
    var getBCHTypeInfo = function(data) {
        var d = data << 10;
        while (getBCHDigit(d) - getBCHDigit(0x537) >= 0) {
            d ^= (0x537 << (getBCHDigit(d) - getBCHDigit(0x537)));
        }
        return ((data << 10) | d) ^ 0x5412;
    };
    
    var getBCHTypeNumber = function(data) {
        var d = data << 12;
        while (getBCHDigit(d) - getBCHDigit(0x1f25) >= 0) {
            d ^= (0x1f25 << (getBCHDigit(d) - getBCHDigit(0x1f25)));
        }
        return (data << 12) | d;
    };
    
    var getBCHDigit = function(data) {
        var digit = 0;
        while (data != 0) {
            digit++;
            data >>>= 1;
        }
        return digit;
    };
    
    var getPatternPosition = function(typeNumber) {
        return [
            [],
            [6, 18],
            [6, 22],
            [6, 26],
            [6, 30],
            [6, 34],
            [6, 22, 38],
            [6, 24, 42],
            [6, 26, 46],
            [6, 28, 50],
            [6, 30, 54],
            [6, 32, 58],
            [6, 34, 62],
            [6, 26, 46, 66],
            [6, 26, 48, 70],
            [6, 26, 50, 74],
            [6, 30, 54, 78],
            [6, 30, 56, 82],
            [6, 30, 58, 86],
            [6, 34, 62, 90],
            [6, 28, 50, 72, 94],
            [6, 26, 50, 74, 98],
            [6, 30, 54, 78, 102],
            [6, 28, 54, 80, 106],
            [6, 32, 58, 84, 110],
            [6, 30, 58, 86, 114],
            [6, 34, 62, 90, 118],
            [6, 26, 50, 74, 98, 122],
            [6, 30, 54, 78, 102, 126],
            [6, 26, 52, 78, 104, 130],
            [6, 30, 56, 82, 108, 134],
            [6, 34, 60, 86, 112, 138],
            [6, 30, 58, 86, 114, 142],
            [6, 34, 62, 90, 118, 146],
            [6, 30, 54, 78, 102, 126, 150],
            [6, 24, 50, 76, 102, 128, 154],
            [6, 28, 54, 80, 106, 132, 158],
            [6, 32, 58, 84, 110, 136, 162],
            [6, 26, 54, 82, 110, 138, 166],
            [6, 30, 58, 86, 114, 142, 170]
        ][typeNumber];
    };
    
    var getRSBlocks = function(typeNumber, errorCorrectLevel) {
        var rsBlock = {
            totalCount: 0,
            dataCount: 0
        };
        
        switch (typeNumber) {
            case 1: rsBlock.totalCount = 26; rsBlock.dataCount = 19; break;
            case 2: rsBlock.totalCount = 44; rsBlock.dataCount = 34; break;
            case 3: rsBlock.totalCount = 70; rsBlock.dataCount = 55; break;
            case 4: rsBlock.totalCount = 100; rsBlock.dataCount = 80; break;
            case 5: rsBlock.totalCount = 134; rsBlock.dataCount = 108; break;
            default: rsBlock.totalCount = 26; rsBlock.dataCount = 19; break;
        }
        
        return [rsBlock];
    };
    
    var getErrorCorrectPolynomial = function(errorCorrectLength) {
        var a = {
            num: [1],
            getAt: function(i) {
                return this.num[i];
            },
            getLength: function() {
                return this.num.length;
            }
        };
        
        for (var i = 0; i < errorCorrectLength; i++) {
            a = multiply(a, {
                num: [1, glog(i)],
                getAt: function(i) {
                    return this.num[i];
                },
                getLength: function() {
                    return this.num.length;
                }
            });
        }
        
        return a;
    };
    
    var multiply = function(e1, e2) {
        var num = new Array(e1.getLength() + e2.getLength() - 1);
        for (var i = 0; i < num.length; i++) {
            num[i] = 0;
        }
        
        for (var i = 0; i < e1.getLength(); i++) {
            for (var j = 0; j < e2.getLength(); j++) {
                num[i + j] ^= gexp(glog(e1.getAt(i)) + glog(e2.getAt(j)));
            }
        }
        
        return {
            num: num,
            getAt: function(i) {
                return this.num[i];
            },
            getLength: function() {
                return this.num.length;
            }
        };
    };
    
    var mod = function(e1, e2) {
        if (e1.getLength() - e2.getLength() < 0) {
            return e1;
        }
        
        var ratio = glog(e1.getAt(0)) - glog(e2.getAt(0));
        var num = new Array(e1.getLength());
        for (var i = 0; i < num.length; i++) {
            num[i] = e1.getAt(i);
        }
        
        for (var i = 0; i < e2.getLength(); i++) {
            num[i] ^= gexp(glog(e2.getAt(i)) + ratio);
        }
        
        return mod({
            num: num,
            getAt: function(i) {
                return this.num[i];
            },
            getLength: function() {
                return this.num.length;
            }
        }, e2);
    };
    
    var glog = function(n) {
        if (n < 1) throw new Error("glog(" + n + ")");
        return LOG_TABLE[n];
    };
    
    var gexp = function(n) {
        while (n < 0) n += 255;
        while (n >= 256) n -= 255;
        return EXP_TABLE[n];
    };
    
    var EXP_TABLE = new Array(256);
    var LOG_TABLE = new Array(256);
    
    for (var i = 0; i < 8; i++) {
        EXP_TABLE[i] = 1 << i;
    }
    for (var i = 8; i < 256; i++) {
        EXP_TABLE[i] = EXP_TABLE[i - 4] ^ EXP_TABLE[i - 5] ^ EXP_TABLE[i - 6] ^ EXP_TABLE[i - 8];
    }
    for (var i = 0; i < 255; i++) {
        LOG_TABLE[EXP_TABLE[i]] = i;
    }
    
    return qr;
};

// Auto-detect best type number
qrcode.stringToBytes = function(s) {
    var bytes = [];
    for (var i = 0; i < s.length; i++) {
        var c = s.charCodeAt(i);
        if (c < 0x80) {
            bytes.push(c);
        } else if (c < 0x800) {
            bytes.push(0xc0 | (c >> 6));
            bytes.push(0x80 | (c & 0x3f));
        } else if (c < 0xd800 || c >= 0xe000) {
            bytes.push(0xe0 | (c >> 12));
            bytes.push(0x80 | ((c >> 6) & 0x3f));
            bytes.push(0x80 | (c & 0x3f));
        } else {
            i++;
            c = 0x10000 + (((c & 0x3ff) << 10) | (s.charCodeAt(i) & 0x3ff));
            bytes.push(0xf0 | (c >> 18));
            bytes.push(0x80 | ((c >> 12) & 0x3f));
            bytes.push(0x80 | ((c >> 6) & 0x3f));
            bytes.push(0x80 | (c & 0x3f));
        }
    }
    return bytes;
};

// Export for global use
if (typeof window !== 'undefined') {
    window.qrcode = qrcode;
}